={{ (() => {
  const b = $json.body || {};
  const status = b.status || 'down';
  const name = b.name || 'Unbekannter Check';
  const desc = b.desc || '';
  const tags = (b.tags || '').split(' ').filter(Boolean).map(t => '#' + t).join(' ');
  const checkUrl = b.check_url || 'https://hc.paun01.de';
  const fmtTime = (iso) => {
    if (!iso) return '–';
    return new Date(iso).toLocaleString('de-DE', {day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'});
  };
  const lastPing = fmtTime(b.last_ping);
  const isUp = status === 'up';
  const header = isUp
    ? '✅ *Health Check erholt*'
    : status === 'failure'
      ? '🟠 *Health Check – Exit-Fehler*'
      : '🔴 *Health Check ausgefallen*';
  let msg = header + '\n\n';
  msg += '📋 *' + name + '*\n';
  msg += (isUp ? '⏰ Wieder aktiv: ' : '⏰ Letzter Ping: ') + lastPing + '\n';
  if (desc) msg += '📝 ' + desc + '\n';
  if (tags) msg += '🏷 ' + tags + '\n';
  msg += '\n[Details bei Healthchecks öffnen](' + checkUrl + ')';
  return msg;
})() }}

